class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        priority_queue<pair<int, int>> pq;
        vector<int> edges_strength(n, 0);
        int max_stability = -1;

        for (auto edge: edges) {
            edges_strength[edge[0]] = edge[2];
            pq.push({edges_strength[edge[0] + edges_strength[edge[1] + edges_strength[edge[2] + edges_strength[edge[3]]);
        }

        while (!pq.empty()) {
            int min_strength = pq.top().first;
            pq.pop();
            max_stability = max(max_stability, min_strength);
        }

        return max_stability;
    }
};
